#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
int n,k;
char a[N];
bool check(long long num){
    int sum=1,s[2]={0,0};
    for(int i=1;i<=n;i++){
        s[a[i]-'0']++;
        if(1LL*s[0]*s[1]>num)
            s[0]=s[1]=0,s[a[i]-'0']=1,sum++;
    }
    return sum<=k;
}
int main(){
    scanf("%d%d",&n,&k);
    scanf("%s",a+1);
    int s1=0,s2=0;
    for(int i=1;i<=n;i++)
        if(a[i]-'0')
            s2++;
        else
            s1++;
    long long l=0,r=1LL*s1*s2;
    while(l<r){
        long long mid=l+r>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%lld",l);
    return 0;
}
